// 模拟 zswps 校对逻辑：检查并修复编号格式
var doc = Application.ActiveDocument;
if (!doc) { throw new Error('未找到活动文档'); }

var paras = doc.Paragraphs;
var count = paras.Count;
var fixedCount = 0;
var commentedCount = 0;
var issues = [];

// 简单的编号规则检查（示例：章节编号连续性）
var chapterPattern = /^第([一二三四五六七八九十百千]+)(章|节)/;
var lastChapterNum = -1;
var currentChapterLevel = 0;

for (var i = 0; i < count; i++) {
    var para = paras.Item(i + 1); // WPS JS 索引从 1 开始
    var text = para.Range.Text.replace(/\r\n/g, '').replace(/\n/g, '');

    if (text.trim().length === 0) continue;

    var match = text.match(chapterPattern);
    if (match) {
        var numStr = match[1];
        var level = match[2] === '章' ? 1 : 2;

        // 将中文数字转为阿拉伯数字
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10,'百':100,'千':1000};
        var num = 0;
        for (var j = 0; j < numStr.length; j++) {
            var char = numStr[j];
            if (numMap[char]) {
                num += numMap[char];
            }
        }

        if (lastChapterNum !== -1 && level === currentChapterLevel) {
            if (num !== lastChapterNum + 1) {
                // 编号不连续，添加批注
                var comment = para.Range.Comments.Add(para.Range);
                comment.Text = '编号不连续：应为第' + (lastChapterNum + 1) + (match[2]) + '，当前为' + numStr + match[2];
                commentedCount++;
                issues.push({type: 'N-00' + level, desc: '编号不连续', range: i});
            }
        }
        lastChapterNum = num;
        currentChapterLevel = level;
    }
}

return {
    totalFixed: fixedCount,
    totalCommented: commentedCount,
    issues: issues,
    summary: '已检查 ' + count + ' 个段落，发现 ' + commentedCount + ' 处编号问题并已添加批注。'
};
